752	function selectSessionCheckpointEntry(card: EntireSessionCard): SessionCheckpointEntry | undefined {
753		const entries = card.checkpointEntries ?? [];
754		if (entries.length === 0) {
755			return undefined;
756		}
757	
758		return [...entries].sort((left, right) => {
759			if (card.latestCheckpointId) {
760				const leftMatchesLatest = left.checkpointId === card.latestCheckpointId ? 1 : 0;
761				const rightMatchesLatest = right.checkpointId === card.latestCheckpointId ? 1 : 0;
762				if (leftMatchesLatest !== rightMatchesLatest) {
763					return rightMatchesLatest - leftMatchesLatest;
764				}
765			}
766	
767			const leftTimestamp = Date.parse(left.session.metadata.createdAt ?? "");
768			const rightTimestamp = Date.parse(right.session.metadata.createdAt ?? "");
769			if (leftTimestamp !== rightTimestamp) {
770				return (Number.isNaN(rightTimestamp) ? 0 : rightTimestamp) - (Number.isNaN(leftTimestamp) ? 0 : leftTimestamp);
771			}
772	
773			return right.sessionIndex - left.sessionIndex;
774		})[0];
